window.renderLocalTimes=function(n){(n||document).querySelectorAll("time").forEach(n=>{var i=n.dateTime,t=new Date(i),r=n.getAttribute("data-dateFormat");n.textContent=r=="M/dd"?t.toLocaleString(undefined,{month:"numeric",day:"2-digit"}):t.toLocaleString()})};document.addEventListener("DOMContentLoaded",()=>{window.renderLocalTimes(),document.body.offsetHeight});